<ul data-start="485" data-end="815">
<li data-start="485" data-end="529">
<p data-start="487" data-end="529">Average Salary: 38,400 TRY (<strong data-start="513" data-end="526">≈ 936 USD</strong>)</p>
</li>
<li data-start="530" data-end="722">
