<li data-start="559" data-end="597">
<p data-start="561" data-end="597">0–1 year: 29,300 TRY (<strong data-start="581" data-end="594">≈ 714 USD</strong>)</p>
</li>
<li data-start="600" data-end="638">
<p data-start="602" data-end="638">2–4 years: 35,500 TRY (<strong data-start="622" data-end="635">≈ 866 USD</strong>)</p>
</li>
<li data-start="641" data-end="679">
<p data-start="643" data-end="679">5–9 years: 40,400 TRY (<strong data-start="663" data-end="676">≈ 985 USD</strong>)</p>
</li>
<li data-start="682" data-end="722">
<p data-start="684" data-end="722">10+ years: 42,300 TRY (<strong data-start="704" data-end="719">≈ 1,032 USD</strong>)</p>
</li>
</ul>
</li>
<li data-start="723" data-end="767">
<p data-start="725" data-end="767">Lowest Salary: 26,200 TRY (<strong data-start="751" data-end="764">≈ 639 USD</strong>)</p>
</li>
<li data-start="768" data-end="815">
<p data-start="770" data-end="815">Highest Salary: 55,800 TRY (<strong data-start="797" data-end="812">≈ 1,360 USD</strong>)</p>
</li>
</ul>
<p data-start="822" data-end="848"><strong>Social Media Specialist</strong></p>
<ul data-start="849" data-end="893">
<li data-start="849" data-end="893">
